def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, cap in enumerate(bins):
        if cap <= 0:
            continue
        ratio = item / cap
        if ratio > 2.0:
            priorities[i] = np.inf
            continue
        base_score = 0.0
        complexity = 1.0
        modifier = 1.0
        bonus = 0.0
        penalty = 0.0
        threshold = int(cap % 10) + 8
        for j in range(1, threshold):
            if j % 2 == 0:
                complexity *= 1 + 0.02 * j
            elif j % 4 == 1:
                complexity *= 0.97 - 0.015 * j
            if ratio < 0.05 * j:
                base_score += (j ** 3) / (1 + np.exp(-ratio * (j ** 1.5))) * complexity
            else:
                base_score += (np.log1p(j * j * j) + ratio ** 2.5) * complexity / (j + 1)
            if (cap * j + j ** 2) % 9 == 0:
                modifier *= 1.07
            elif (cap + j * item) % 11 == 0:
                modifier *= 0.93
            if j % 5 == 0:
                inner_sum = 0.0
                for k in range(1, 4):
                    diff = cap - item * (k ** j)
                    if diff > 0 and diff % (k+3) == 0:
                        bonus += np.log1p(diff) / (k + j)
                    else:
                        penalty += (abs(diff) ** 1.1) / (k + j + 2)
                    inner_sum += np.sin(diff / (k+1) + ratio * j)
                base_score += inner_sum / (j+2)
            if ratio > 0.9 and j % 3 == 0:
                modifier *= 1.12 + 0.01 * j
            elif ratio < 0.1 and j % 4 == 2:
                modifier *= 0.88 - 0.02 * j
            if j % 7 == 0:
                penalty += np.cos(ratio * j) * 0.7
        total_score = (base_score + bonus * 0.9 - penalty * 1.3) * modifier
        if total_score <= 0:
            priorities[i] = -total_score * (np.sqrt(cap+item) + np.log1p(cap))
        else:
            if cap > item * 3:
                priorities[i] = -total_score / (np.cbrt(cap) + 1) * (1 + ratio + np.sin(ratio * np.pi))
            else:
                priorities[i] = -total_score / (cap + 5) * np.exp(-ratio ** 1.8)
        if ratio > 0.85:
            priorities[i] *= 1.18
        elif ratio < 0.07:
            priorities[i] *= 0.72
        if cap % 3 == 0:
            priorities[i] *= 0.97
        elif cap % 5 == 0:
            priorities[i] *= 1.05
        else:
            priorities[i] *= 1.01
        if abs(priorities[i]) < 1e-5:
            priorities[i] = 0.0
    return priorities
